var e=[{id:`L2_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`위험해.`,JPN:`危ない。`,ENG:`This isn't good.`,TWN:`危險。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`역신의 피가 녀석의 영혼을 태워 결계를 만들고 있다.`,JPN:`疫病神の血が奴の魂を燃やして結界を作っている。`,ENG:`The Plague God's blood is creating a barrier by burning her soul.`,TWN:`瘟神血液正在燃燒她的靈魂產生結界。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`DRAGON_NANAHARA_NULL_NULL`,text:{KOREA:`당주! 일단 물러서라! 지금 녀석에게 다가가면 너도 무사하지 못해!`,JPN:`当主！　一旦引け！　今奴に近づいたら、お主も無事では済まないぞ！`,ENG:`Lady Nanahara! Get back! If you get close to her now, I can't guarantee your safety!`,TWN:`堂主！先退下！現在靠她太近你也會有危險！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`DRAGON_NANAHARA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`그래서는 늦고 맙니다.`,JPN:`それでは遅れてしまいます。`,ENG:`By then, it will be too late.`,TWN:`我怕再耽擱下去會太遲。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`치후유를 혼자 괴로워하게 둘 수는 없어요.`,JPN:`千冬を一人苦しませるわけにはいきません。`,ENG:`I cannot let Chifuyu suffer alone.`,TWN:`我不能放千冬一個人痛苦。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`다가가는 것만으로도…… 살갗이 찢기는 것 같아.`,JPN:`近づくだけでも……肌が切り裂かれるみたい。`,ENG:`Just be getting close to her... I feel a thousand cuts ripping my skin.`,TWN:`光是靠近她……我的皮膚就彷彿被撕裂一般。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_HATE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`그래도……`,JPN:`それでも……`,ENG:`But still...`,TWN:`就算如此……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`어떻게든 닿아야 해.`,JPN:`どにかして行かなければ。`,ENG:`I must reach her.`,TWN:`無論如何我都要靠近她。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`으윽……!`,JPN:`ううっ……！`,ENG:`Ngh...!`,TWN:`呃啊……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`<color=#ff3636>크아아아아아!!!!</color>`,JPN:`<color=#ff3636>グアアアアア！！！！</color>`,ENG:`<color=#ff3636>Groarr!!</color>`,TWN:`<color=#ff3636>呃啊啊啊啊啊！！！</color>`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L15_1`,type:`narration`,speaker:null,text:{KOREA:`뭘 하고 있는 거냐, 나는…….`,JPN:`何をやっているんだ、私は……`,ENG:`What am I even doing...?`,TWN:`我，到底在做什麼……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`narration`,speaker:null,text:{KOREA:`짐승이나 된 것처럼 고함이나 지르고 있고.`,JPN:`獣になったみたいに叫んでばかり。`,ENG:`I'm like an uncontrollable beast, roaring at the top of my lungs.`,TWN:`我彷彿像野獸般，在那嚎叫。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:`당주님?`,JPN:`当主？`,ENG:`Lady Nanahara?`,TWN:`堂主？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:null,text:{KOREA:`지금 내가…… 당주님을 해치려고 하는 건가?`,JPN:`今私が……当主を攻撃しようとしているのか？`,ENG:`Am I... trying to harm her?`,TWN:`我現在……是要傷害堂主嗎？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`네 평생을 걸었던 사람을 눈 앞에 두고…….`,JPN:`一生をかけて守ろうとした人を目の前にして……`,ENG:`She is the one person I swore to protect...`,TWN:`我賭上一輩子要守護的人，就在我面前……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`넌 고작 이런 결말을 위해 지금껏 노력했던 거냐.`,JPN:`お前はこんな結末を迎えるために今まで頑張ってきたのか。`,ENG:`Did I go through everything just so it could end like this?`,TWN:`難道我是因為要得到這種結局，才努力到現在的嗎？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}}];export{e as default};